const presentationId  = $input.item.json.presentationId;
const slides          = $('Code in JavaScript1').item.json.slides;
const engagement_id   = $('Code in JavaScript1').item.json.engagement_id;
const deck_title      = $('Code in JavaScript1').item.json.deck_title;
const deck_type       = $('Code in JavaScript1').item.json.deck_type || 'gtm';
const client_name     = $('Code in JavaScript1').item.json.client_name || 'Confidential';
const presentationUrl = 'https://docs.google.com/presentation/d/' + presentationId + '/edit';
const W = 9144000; const H = 5143500;
const NAVY   = { red: 0.118, green: 0.224, blue: 0.392 };
const ORANGE = { red: 0.929, green: 0.314, blue: 0.165 };
const WHITE  = { red: 1,     green: 1,     blue: 1     };
const DARK   = { red: 0.13,  green: 0.13,  blue: 0.13  };
const MID    = { red: 0.42,  green: 0.42,  blue: 0.42  };
const LTBLUE = { red: 0.80,  green: 0.85,  blue: 0.90  };
const MARGIN    = 320040;
const TOP_BAR_H = 300000;
const FOOTER_H  = 160000;
function uid() { return 'el' + Math.random().toString(36).slice(2, 11); }
function clean(s) { return (s || '').replace(/\*\*/g, '').replace(/\*/g, '').trim(); }
function truncate(s, max) { s = clean(s); return s.length > max ? s.slice(0, max - 3) + '...' : s; }
function buildChartUrl(chart) {
  var type = chart.type || 'bar';
  var COLORS = ['#1E3A64','#ED5029','#2E86AB','#A23B72','#F18F01','#3D9970'];
  var isLine = (type === 'line');
  var datasets = chart.datasets.map(function(d, i) {
    var bg = d.color || COLORS[i % COLORS.length];
    return { label: d.label, data: d.data, backgroundColor: isLine ? (bg + '33') : bg, borderColor: bg, borderWidth: isLine ? 3 : 0, pointBackgroundColor: bg, pointRadius: isLine ? 4 : 0, fill: isLine };
  });
  var config = {
    type: type,
    data: { labels: chart.labels, datasets: datasets },
    options: {
      title: { display: !!(chart.title), text: chart.title || '', fontColor: '#1E3A64', fontSize: 15, fontStyle: 'bold', padding: 12 },
      legend: { display: datasets.length > 1, labels: { fontColor: '#333', fontSize: 12, padding: 16 } },
      scales: (type === 'doughnut' || type === 'pie') ? {} : { xAxes: [{ ticks: { fontColor: '#444', fontSize: 12, maxRotation: 35 }, gridLines: { color: '#e8e8e8', zeroLineColor: '#bbb' } }], yAxes: [{ ticks: { fontColor: '#444', fontSize: 12, beginAtZero: true }, gridLines: { color: '#e8e8e8', zeroLineColor: '#bbb' } }] },
      layout: { padding: { left: 10, right: 10, top: 5, bottom: 10 } },
      plugins: { datalabels: { display: false } }
    }
  };
  return 'https://quickchart.io/chart?w=720&h=440&bkg=white&c=' + encodeURIComponent(JSON.stringify(config));
}
function rect(pageId, x, y, w, h, color) {
  var id = uid();
  return [
    { createShape: { objectId: id, shapeType: 'RECTANGLE', elementProperties: { pageObjectId: pageId, size: { width: { magnitude: w, unit: 'EMU' }, height: { magnitude: h, unit: 'EMU' } }, transform: { scaleX: 1, scaleY: 1, translateX: x, translateY: y, unit: 'EMU' } } } },
    { updateShapeProperties: { objectId: id, shapeProperties: { shapeBackgroundFill: { solidFill: { color: { rgbColor: color } } }, outline: { outlineFill: { solidFill: { color: { rgbColor: color } } } } }, fields: 'shapeBackgroundFill,outline' } }
  ];
}
function textBox(pageId, text, x, y, w, h, opts) {
  var id = uid();
  var reqs = [
    { createShape: { objectId: id, shapeType: 'TEXT_BOX', elementProperties: { pageObjectId: pageId, size: { width: { magnitude: w, unit: 'EMU' }, height: { magnitude: h, unit: 'EMU' } }, transform: { scaleX: 1, scaleY: 1, translateX: x, translateY: y, unit: 'EMU' } } } },
    { insertText: { objectId: id, text: text } },
    { updateTextStyle: { objectId: id, textRange: { type: 'ALL' }, style: { bold: opts.bold || false, italic: opts.italic || false, fontSize: { magnitude: opts.size || 14, unit: 'PT' }, foregroundColor: { opaqueColor: { rgbColor: opts.color || DARK } }, fontFamily: 'Calibri' }, fields: 'bold,italic,fontSize,foregroundColor,fontFamily' } }
  ];
  if (opts.align || opts.lineSpacing || opts.spaceAbove) {
    var ps = {}; var pf = [];
    if (opts.align)       { ps.alignment = opts.align; pf.push('alignment'); }
    if (opts.lineSpacing) { ps.lineSpacing = opts.lineSpacing; pf.push('lineSpacing'); }
    if (opts.spaceAbove)  { ps.spaceAbove = { magnitude: opts.spaceAbove, unit: 'EMU' }; pf.push('spaceAbove'); }
    reqs.push({ updateParagraphStyle: { objectId: id, textRange: { type: 'ALL' }, style: ps, fields: pf.join(',') } });
  }
  return reqs;
}
function renderBullets(slideId, bullets, startX, startY, colW, maxBottom) {
  var reqs = []; var y = startY;
  var BULLET_H = 420000; var SUB_H = 290000; var GROUP_GAP = 70000; var SUB_GAP = 18000;
  var INDENT = 260000; var ACCENT_W = 40000; var ACCENT_GAP = 40000;
  bullets.forEach(function(b) {
    if (y + BULLET_H > maxBottom) return;
    var item = (typeof b === 'string') ? { text: b, sub_points: [] } : b;
    var mainText = truncate(item.text, 120);
    var accentId = uid();
    reqs.push({ createShape: { objectId: accentId, shapeType: 'RECTANGLE', elementProperties: { pageObjectId: slideId, size: { width: { magnitude: ACCENT_W, unit: 'EMU' }, height: { magnitude: BULLET_H - 80000, unit: 'EMU' } }, transform: { scaleX: 1, scaleY: 1, translateX: startX, translateY: y + 40000, unit: 'EMU' } } } });
    reqs.push({ updateShapeProperties: { objectId: accentId, shapeProperties: { shapeBackgroundFill: { solidFill: { color: { rgbColor: ORANGE } } }, outline: { outlineFill: { solidFill: { color: { rgbColor: ORANGE } } } } }, fields: 'shapeBackgroundFill,outline' } });
    textBox(slideId, mainText, startX + ACCENT_W + ACCENT_GAP, y, colW - ACCENT_W - ACCENT_GAP, BULLET_H, { bold: true, size: 14, color: NAVY, lineSpacing: 115 }).forEach(function(r) { reqs.push(r); });
    y += BULLET_H + 14000;
    (item.sub_points || []).slice(0, 2).forEach(function(sp) {
      if (y + SUB_H > maxBottom) return;
      textBox(slideId, '-   ' + truncate(sp, 100), startX + INDENT, y, colW - INDENT, SUB_H, { bold: false, size: 12, color: MID, lineSpacing: 112 }).forEach(function(r) { reqs.push(r); });
      y += SUB_H + SUB_GAP;
    });
    y += GROUP_GAP;
  });
  return reqs;
}
var requests = [];
slides.forEach(function(slide, idx) {
  var slideId = uid();
  requests.push({ createSlide: { objectId: slideId, insertionIndex: idx, slideLayoutReference: { predefinedLayout: 'BLANK' } } });
  if (slide.type === 'title') {
    requests.push({ updatePageProperties: { objectId: slideId, pageProperties: { pageBackgroundFill: { solidFill: { color: { rgbColor: NAVY } } } }, fields: 'pageBackgroundFill' } });
    rect(slideId, 0, H - 760000, W, 760000, ORANGE).forEach(function(r) { requests.push(r); });
    rect(slideId, MARGIN, 900000, 760000, 18288, ORANGE).forEach(function(r) { requests.push(r); });
    textBox(slideId, clean(slide.title || deck_title), MARGIN, 1000000, W - 2 * MARGIN, 1800000, { bold: true, size: 40, color: WHITE, align: 'START', lineSpacing: 108 }).forEach(function(r) { requests.push(r); });
    if (slide.subtitle) { textBox(slideId, clean(slide.subtitle), MARGIN, 2900000, W - 2 * MARGIN, 400000, { bold: false, size: 17, color: LTBLUE, align: 'START' }).forEach(function(r) { requests.push(r); }); }
  } else if (slide.type === 'section_header') {
    requests.push({ updatePageProperties: { objectId: slideId, pageProperties: { pageBackgroundFill: { solidFill: { color: { rgbColor: NAVY } } } }, fields: 'pageBackgroundFill' } });
    rect(slideId, 0, 0, 120000, H, ORANGE).forEach(function(r) { requests.push(r); });
    var titleY = Math.floor(H / 2) - 600000;
    textBox(slideId, clean(slide.title || ''), 220000, titleY, W - 340000, 900000, { bold: true, size: 36, color: WHITE, align: 'START', lineSpacing: 108 }).forEach(function(r) { requests.push(r); });
    rect(slideId, 220000, titleY + 960000, 900000, 18288, ORANGE).forEach(function(r) { requests.push(r); });
    if (slide.subtitle) { textBox(slideId, clean(slide.subtitle), 220000, titleY + 1040000, W - 340000, 400000, { bold: false, size: 16, color: LTBLUE, align: 'START' }).forEach(function(r) { requests.push(r); }); }
    textBox(slideId, String(idx + 1), W - 500000, H - 300000, 400000, 260000, { size: 10, color: LTBLUE, align: 'END' }).forEach(function(r) { requests.push(r); });
  } else {
    var hasChart = !!(slide.chart && slide.chart.labels && slide.chart.datasets && slide.chart.datasets.length > 0);
    requests.push({ updatePageProperties: { objectId: slideId, pageProperties: { pageBackgroundFill: { solidFill: { color: { rgbColor: WHITE } } } }, fields: 'pageBackgroundFill' } });
    rect(slideId, 0, 0, W, TOP_BAR_H, NAVY).forEach(function(r) { requests.push(r); });
    rect(slideId, 0, 0, 80000, TOP_BAR_H, ORANGE).forEach(function(r) { requests.push(r); });
    textBox(slideId, truncate(slide.title || '', 90), 150000, 20000, W - 200000, TOP_BAR_H - 20000, { bold: true, size: 16, color: WHITE, lineSpacing: 100 }).forEach(function(r) { requests.push(r); });
    var contentY = TOP_BAR_H + 45000;
    if (slide.subtitle) {
      textBox(slideId, truncate(slide.subtitle, 130), MARGIN, contentY, W - 2 * MARGIN, 240000, { italic: true, size: 12, color: MID, lineSpacing: 108 }).forEach(function(r) { requests.push(r); });
      contentY += 256000;
    }
    rect(slideId, MARGIN, contentY, W - 2 * MARGIN, 10000, ORANGE).forEach(function(r) { requests.push(r); });
    contentY += 55000;
    var maxBottom = H - FOOTER_H - 50000;
    var slideBullets = slide.bullets || [];
    if (hasChart) {
      var colW = Math.floor((W - 3 * MARGIN) / 2);
      renderBullets(slideId, slideBullets, MARGIN, contentY, colW, maxBottom).forEach(function(r) { requests.push(r); });
      var chartUrl = buildChartUrl(slide.chart);
      var chartH = Math.min(maxBottom - contentY, 2500000);
      var chartImgId = uid();
      requests.push({ createImage: { objectId: chartImgId, url: chartUrl, elementProperties: { pageObjectId: slideId, size: { width: { magnitude: colW, unit: 'EMU' }, height: { magnitude: chartH, unit: 'EMU' } }, transform: { scaleX: 1, scaleY: 1, translateX: 2 * MARGIN + colW, translateY: contentY, unit: 'EMU' } } } });
    } else {
      renderBullets(slideId, slideBullets, MARGIN, contentY, W - 2 * MARGIN, maxBottom).forEach(function(r) { requests.push(r); });
    }
    rect(slideId, 0, H - FOOTER_H, W, FOOTER_H, NAVY).forEach(function(r) { requests.push(r); });
    textBox(slideId, deck_title + '   |   ' + (idx + 1), MARGIN, H - FOOTER_H + 25000, W - 2 * MARGIN, FOOTER_H, { size: 8, color: LTBLUE, align: 'CENTER' }).forEach(function(r) { requests.push(r); });
  }
});
return { json: { presentation_id: presentationId, presentation_url: presentationUrl, batch_payload: JSON.stringify({ requests }), engagement_id, deck_title, deck_type, client_name } };
